import sailpoint.object.ResourceObject;
    import sailpoint.api.SailPointContext;
    import org.apache.log4j.Logger;
    import sailpoint.tools.Util;
    import sailpoint.object.Custom;
    import sailpoint.object.Attributes;
    import sailpoint.api.PersistenceManager;
    import sailpoint.api.ObjectUtil;
	 import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Identity;
  import java.util.regex.Matcher;
  import java.util.regex.Pattern;

    Logger logger = Logger.getLogger("sailpoint.ascension.rules.AD.account.Customization");

    String emailAddress;
    String sAMAccountName;
    Object proxyAddresses;
    List updatedProxyAddresses = new ArrayList();

    if(void !=object  && null!= object) {
        sAMAccountName = object.getStringAttribute("sAMAccountName");
	if (Util.isNotNullOrEmpty(sAMAccountName) && (sAMAccountName.startsWith("$") || sAMAccountName.startsWith("!") || sAMAccountName.startsWith("_") || sAMAccountName.startsWith("~") || sAMAccountName.toLowerCase().startsWith("citrix") || "citrixtest".equalsIgnoreCase(sAMAccountName) || "spadmin".equalsIgnoreCase(sAMAccountName))) {
           return null;
        }
        
        emailAddress = object.getStringAttribute("mail");
        if (Util.isNotNullOrEmpty(emailAddress)) {
            emailAddress = object.getAttribute("mail").toString().toLowerCase();
            object.setAttribute("mail",emailAddress);
        }
      	Object mobileObj = object.getAttribute("telephoneNumber");
        if (mobileObj != null) {
            String mobTempValue = mobileObj.toString();
            String mobFinalValue = null;
            if(Util.isNotNullOrEmpty(mobTempValue)){
                String regex = "\\((\\d{3})\\) (\\d{3})-(\\d{4})";
                String replacement = "$1-$2-$3";
                Pattern pattern = Pattern.compile(regex);
                Matcher matcher = pattern.matcher(mobTempValue);
                if (matcher.find()) {
                    mobFinalValue = matcher.replaceAll(replacement);
                    object.setAttribute("telephoneNumber",mobFinalValue);
                }                            
            }
        }
        Object departmentNumberObj = object.getAttribute("departmentNumber");
        if (departmentNumberObj != null) {
            String tempValue = departmentNumberObj.toString();
            if(Util.isNotNullOrEmpty(tempValue)){
                object.setAttribute("departmentNumber",encryptAES(tempValue));
            }
        }
        Object employeeTypeObj = object.getAttribute("employeeType");
        if (null!=employeeTypeObj) {
            String tempValue = employeeTypeObj.toString();
            if(Util.isNotNullOrEmpty(tempValue)){
                object.setAttribute("employeeType",encryptAES(tempValue));
            }
        }
        if(void !=object.getAttribute("employeeNumber")  && null!=object.getAttribute("employeeNumber")) {          
            object.setAttribute("primaryADAccount",true);
        }
        else{
            object.setAttribute("primaryADAccount",false);
        }

        //Get all the do-not-provision domains from Custom object
        List exludeAliasesDomainList = new ArrayList();
        Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-Gsuite");
        if(custom != null) {
            Attributes attrMap = custom.getAttributes();
            if(attrMap != null) {
                exludeAliasesDomainList = attrMap.get("gsuite_excluded_aliasses");
            }
        }
        
        if (void!=object.getAttribute("proxyAddresses") && null!=object.getAttribute("proxyAddresses")) {
			proxyAddresses = object.getAttribute("proxyAddresses");
			String mailAddress = object.getAttribute("mail");     
			if (proxyAddresses instanceof String) {
				boolean excludeFlag = false;
							
				for(String aliasDomain : exludeAliasesDomainList) {
					String domainCeck = proxyAddresses.substring(proxyAddresses.indexOf("@")+1, proxyAddresses.length()).toLowerCase();
					if(aliasDomain.equalsIgnoreCase(domainCeck)) {
						excludeFlag = true;
						break;
					}
				}
        
        if(proxyAddresses.toLowerCase().startsWith("x500:") || proxyAddresses.contains("?") || proxyAddresses.contains("$")){
					excludeFlag = true;
			  }
        
				if (!excludeFlag) {
					if (Util.isNotNullOrEmpty(mailAddress) && !proxyAddresses.equalsIgnoreCase("SMTP:" + mailAddress) &&
						Util.isNotNullOrEmpty(mailAddress) && !proxyAddresses.equalsIgnoreCase("SIP:" + mailAddress) &&
						Util.isNotNullOrEmpty(mailAddress) && !proxyAddresses.equalsIgnoreCase("X500:" + mailAddress)) {
						String address = "";
						if (proxyAddresses.toLowerCase().startsWith("smtp:")) {
							address = proxyAddresses.substring(5, proxyAddresses.length()).toLowerCase();  
							object.setAttribute("proxyAddresses", address);		
						} else if (proxyAddresses.toLowerCase().startsWith("sip:")) {
							address = proxyAddresses.substring(4, proxyAddresses.length()).toLowerCase();
						} else if (proxyAddresses.toLowerCase().startsWith("x500:")) {
							address = proxyAddresses.substring(5, proxyAddresses.length()).toLowerCase();
						} else {
							address = address.toLowerCase();
						}						
					}
				}
			} else if (proxyAddresses instanceof List) {
				//Exclude out aliases that match the AD domains, we dont want provisioned into GSuite.
				List proxyValues = Util.otol(proxyAddresses);
				for (String address: proxyValues) {
					if (void!=address && null!=address) {
						boolean excludeFlag = false;
						if(address.toLowerCase().startsWith("x500:") || address.contains("?") || address.contains("$")){
							excludeFlag = true;
						}
						
						if(!excludeFlag){
							for(String aliasDomain : exludeAliasesDomainList) {
								String domainCeck = address.substring(address.indexOf("@")+1, address.length()).toLowerCase();
								if(aliasDomain.equalsIgnoreCase(domainCeck)) {
									excludeFlag = true;
								}
							}
						}
						if (!excludeFlag) {
							if (Util.isNotNullOrEmpty(mailAddress) && !address.equalsIgnoreCase("SMTP:" + mailAddress)) {
								if (address.toLowerCase().startsWith("smtp:")) {
									address = address.substring(5,address.length()).toLowerCase();
									updatedProxyAddresses.add(address);
								}
							}
						}
					} // Address not null check
				} // end loop for
				object.setAttribute("proxyAddresses",updatedProxyAddresses);
			}
			}
			
			 String extensionAttribute39 = object.getAttribute("msExchExtensionAttribute39");
    if (null!=extensionAttribute39 && extensionAttribute39.length() >= 450) {
    	object.setAttribute("msExchExtensionAttribute39", extensionAttribute39.substring(0,450));
		}
		String strLastName=null;
    QueryOptions qryOpt=new QueryOptions();
    Filter f1=Filter.eq("email",object.getStringAttribute("mail"));
    Filter f2=Filter.eq("name",object.getStringAttribute("sAMAccountName"));
    if(object.getStringAttribute("mail")!=null){
      qryOpt.addFilter(f1); 
    }
    else if(object.getStringAttribute("mail")!=null && object.getStringAttribute("sAMAccountName")!=null){
      qryOpt.addFilter(Filter.and(f1,f2));
    }else{
      qryOpt.addFilter(f2);
    }
    Iterator iterator = context.search(Identity.class,qryOpt);          
    if(iterator != null && iterator.hasNext()){

      Identity identity = iterator.next();           
      if(identity.getStringAttribute("lastname") != null){
        strLastName=identity.getStringAttribute("lastname");
      }
    }
        //descriptiveLastName for GSuite
        String sn = object.getAttribute("sn");
        String extensionAttribute42 = object.getAttribute("msExchExtensionAttribute42");
        if (void !=sn && Util.isNotNullOrEmpty(sn)) {
            String descriptiveLastName;
            if (void !=extensionAttribute42 && Util.isNotNullOrEmpty(extensionAttribute42)) {
                descriptiveLastName = sn + " " + extensionAttribute42;
                if (descriptiveLastName.length() <= 60) {
                    object.setAttribute("ASC_GSuite_LastName", descriptiveLastName);
                } else {
                    object.setAttribute("ASC_GSuite_LastName", descriptiveLastName.substring(0,60));
                }
            } else {
                object.setAttribute("ASC_GSuite_LastName", sn);
            } 
        } else{
        if(strLastName!=null){
        object.setAttribute("ASC_GSuite_LastName", strLastName);
        }
      }
  
  }
  return object;
